SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;
DROP TABLE IF EXISTS meal;
DROP TABLE IF EXISTS customerpreference;
DROP TABLE IF EXISTS food;
DROP TABLE IF EXISTS backdown;
DROP TABLE IF EXISTS outward;
DROP TABLE IF EXISTS customernurseitem;
DROP TABLE IF EXISTS nurserecord;
DROP TABLE IF EXISTS nurselevelitem;
DROP TABLE IF EXISTS nurselevel;
DROP TABLE IF EXISTS nursecontent;
DROP TABLE IF EXISTS rolemenu;
DROP TABLE IF EXISTS menu;
DROP TABLE IF EXISTS beddetails;
DROP TABLE IF EXISTS customer;
DROP TABLE IF EXISTS bed;
DROP TABLE IF EXISTS room;
DROP TABLE IF EXISTS `user`;
DROP TABLE IF EXISTS role;
CREATE TABLE role (id INT PRIMARY KEY AUTO_INCREMENT,create_time DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,update_time DATETIME NULL,update_by INT NULL,is_deleted INT NOT NULL DEFAULT 0,name VARCHAR(50) NOT NULL) ENGINE=InnoDB;
CREATE TABLE `user` (id INT PRIMARY KEY AUTO_INCREMENT,create_time DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,create_by INT NULL,update_time DATETIME NULL,update_by INT NULL,is_deleted INT NOT NULL DEFAULT 0,nickname VARCHAR(20) NOT NULL,username VARCHAR(20) NOT NULL UNIQUE,password VARCHAR(100) NOT NULL,sex INT NOT NULL DEFAULT 1,email VARCHAR(254) NULL,phone_number VARCHAR(20) NOT NULL,role_id INT NOT NULL) ENGINE=InnoDB;
CREATE TABLE room (id INT PRIMARY KEY AUTO_INCREMENT,room_floor VARCHAR(10) NOT NULL,room_no INT NOT NULL,UNIQUE KEY uk_room (room_floor, room_no)) ENGINE=InnoDB;
CREATE TABLE bed (id INT PRIMARY KEY AUTO_INCREMENT,room_no INT NOT NULL,bed_status INT NOT NULL DEFAULT 1,remarks VARCHAR(255) NULL,bed_no VARCHAR(20) NOT NULL,room_id INT NULL,KEY idx_bed_room (room_no)) ENGINE=InnoDB;
CREATE TABLE customer (id INT PRIMARY KEY AUTO_INCREMENT,is_deleted INT NOT NULL DEFAULT 0,resident_status INT NOT NULL DEFAULT 1 COMMENT '1在住 2已退住',customer_name VARCHAR(20) NOT NULL,customer_age INT NOT NULL,customer_sex INT NOT NULL,idcard VARCHAR(20) NOT NULL,room_no VARCHAR(20) NOT NULL,building_no VARCHAR(11) NOT NULL DEFAULT '606',checkin_date DATE NOT NULL,expiration_date DATE NOT NULL,contact_tel VARCHAR(20) NOT NULL,bed_id INT NULL,blood_type VARCHAR(20) NOT NULL,filepath VARCHAR(50) NOT NULL DEFAULT '/avatar/default.png',user_id INT NULL DEFAULT -1,level_id INT NULL,family_member VARCHAR(20) NULL,birthday DATE NULL,KEY idx_customer_name (customer_name),KEY idx_resident_status (resident_status)) ENGINE=InnoDB;
CREATE TABLE beddetails (id INT PRIMARY KEY AUTO_INCREMENT,start_date DATE NULL,end_date DATE NULL,bed_details VARCHAR(255) NULL,customer_id INT NULL,bed_id INT NULL,is_deleted INT NOT NULL DEFAULT 0,use_status INT NOT NULL DEFAULT 1 COMMENT '1正在使用 2历史',KEY idx_bd_customer (customer_id)) ENGINE=InnoDB;
CREATE TABLE menu (id INT PRIMARY KEY AUTO_INCREMENT,menus_index VARCHAR(5) NULL,title VARCHAR(50) NOT NULL,icon VARCHAR(50) NOT NULL DEFAULT 'Menu',path VARCHAR(100) NULL,parent_id INT NULL) ENGINE=InnoDB;
CREATE TABLE rolemenu (id INT PRIMARY KEY AUTO_INCREMENT,role_id INT NOT NULL,menu_id INT NOT NULL) ENGINE=InnoDB;
CREATE TABLE nursecontent (id INT PRIMARY KEY AUTO_INCREMENT,serial_number VARCHAR(20) NOT NULL,nursing_name VARCHAR(55) NOT NULL,service_price VARCHAR(55) NOT NULL,message VARCHAR(100) NULL,status INT NOT NULL DEFAULT 1,execution_cycle VARCHAR(20) NULL,execution_times VARCHAR(20) NULL,is_deleted INT NOT NULL DEFAULT 0) ENGINE=InnoDB;
CREATE TABLE nurselevel (id INT PRIMARY KEY AUTO_INCREMENT,level_name VARCHAR(20) NOT NULL,level_status INT NOT NULL DEFAULT 1,is_deleted INT NOT NULL DEFAULT 0) ENGINE=InnoDB;
CREATE TABLE nurselevelitem (id INT PRIMARY KEY AUTO_INCREMENT,level_id INT NOT NULL,item_id INT NOT NULL) ENGINE=InnoDB;
CREATE TABLE customernurseitem (id INT PRIMARY KEY AUTO_INCREMENT,item_id INT NOT NULL,customer_id INT NOT NULL,level_id INT NULL,nurse_number INT NOT NULL DEFAULT 1,is_deleted INT NOT NULL DEFAULT 0,buy_time DATE NOT NULL,maturity_time DATE NOT NULL) ENGINE=InnoDB;
CREATE TABLE nurserecord (id INT PRIMARY KEY AUTO_INCREMENT,is_deleted INT NOT NULL DEFAULT 0,customer_id INT NOT NULL,item_id INT NOT NULL,nursing_time DATETIME NOT NULL,nursing_content VARCHAR(255) NULL,nursing_count INT NOT NULL DEFAULT 1,user_id INT NOT NULL) ENGINE=InnoDB;
CREATE TABLE outward (id INT PRIMARY KEY AUTO_INCREMENT,remarks VARCHAR(100) NULL,is_deleted INT NOT NULL DEFAULT 0,customer_id INT NOT NULL,outgoingreason VARCHAR(100) NOT NULL,outgoingtime DATE NOT NULL,expectedreturntime DATE NOT NULL,actualreturntime DATE NULL,escorted VARCHAR(50) NULL,relation VARCHAR(50) NULL,escortedtel VARCHAR(50) NULL,auditstatus INT NOT NULL DEFAULT 0,auditperson VARCHAR(50) NULL,audittime DATETIME NULL,submit_user_id INT NULL) ENGINE=InnoDB;
CREATE TABLE backdown (id INT PRIMARY KEY AUTO_INCREMENT,remarks VARCHAR(100) NULL,is_deleted INT NOT NULL DEFAULT 0,customer_id INT NOT NULL,retreattime DATE NOT NULL,retreattype INT NOT NULL,retreatreason VARCHAR(100) NULL,auditstatus INT NOT NULL DEFAULT 0,auditperson VARCHAR(50) NULL,audittime DATETIME NULL,submit_user_id INT NULL) ENGINE=InnoDB;
CREATE TABLE food (id INT PRIMARY KEY AUTO_INCREMENT,food_name VARCHAR(30) NULL,food_type VARCHAR(30) NULL,price DECIMAL(10,2) NULL,is_halal INT NULL) ENGINE=InnoDB;
SET FOREIGN_KEY_CHECKS = 1;
